const input = $json ?? {};
const message = input.message ?? {};
const callback = input.callback_query ?? null;
const callbackData = callback?.data ? String(callback.data) : '';
const messageText = typeof message.text === 'string' ? message.text : '';
const callbackText = typeof callback?.message?.text === 'string' ? callback.message.text : '';
const text = messageText || callbackText || '';
const chatIdRaw = message.chat?.id ?? callback?.message?.chat?.id ?? '';
const userIdRaw = message.from?.id ?? callback?.from?.id ?? '';
const messageIdRaw = message.message_id ?? callback?.message?.message_id ?? callback?.id ?? '';
const startMatch = text.match(/^\/start(?:\s+(.+))?$/);
const deepLink = startMatch?.[1] ? String(startMatch[1]).trim() : null;
let eventType = 'text_message';
if (callback) {
  eventType = 'callback_action';
} else if (startMatch) {
  eventType = deepLink ? 'deep_link_start' : 'start_reset';
}
return [{
  json: {
    event: {
      event_type: eventType,
      text,
      chatId: String(chatIdRaw || ''),
      userId: String(userIdRaw || ''),
      messageId: String(messageIdRaw || ''),
      timestamp: Date.now(),
      callback_query: callbackData ? { data: callbackData } : null,
      deep_link: deepLink,
    },
  },
}];

const payload = $json ?? {};
let event = payload.event ?? null;
if (!event) {
  try {
    event = $item(0).$node['Event Normalizer'].json.event;
  } catch {
    event = null;
  }
}
event = event && typeof event === 'object' ? event : {};
const remoteSession = payload.session ?? payload.data?.session ?? null;
const remoteExists = payload.session?.exists ?? payload.data?.session?.exists ?? false;
const rawSessionData = remoteSession?.data ?? remoteSession;
const hasExistingSession = Boolean(remoteExists || (rawSessionData && typeof rawSessionData === 'object' && Object.keys(rawSessionData).length > 0));
let sellerId = '__SELLER_ID_FROM_ENV__';
if (typeof $env !== 'undefined' && $env?.SELLER_ID) {
  sellerId = String($env.SELLER_ID);
}
const now = Date.now();
const baseSession = {
  isNew: true,
  session_version: 2,
  chat_id: String(event.chatId ?? ''),
  seller_id: sellerId,
  language: null,
  stage: 'idle',
  resolved_flow: 'none',
  tentative_flow: 'none',
  next_action: null,
  route_recommendation: 'stay_exploratory',
  followup_round: 0,
  last_asked_key: null,
  collected_fields: {},
  missing_information: [],
  evidence_accumulated: 0,
  message_history: [],
  last_understanding_output: null,
  last_rule_decision: null,
  last_resolver_output: null,
  shown_options: [],
  selected_option: null,
  ranking_order: [],
  cheaper_option: null,
  active_product_id: null,
  deep_link_context: null,
  callback_context: null,
  lead_state: null,
  notify_state: null,
  handoff_state: null,
  recovery_state: null,
  error_count: 0,
  updated_at: now,
};
const session = hasExistingSession
  ? {
      ...baseSession,
      ...(rawSessionData && typeof rawSessionData === 'object' ? rawSessionData : {}),
      isNew: false,
      chat_id: String((rawSessionData && rawSessionData.chat_id) || event.chatId || ''),
      seller_id: String((rawSessionData && rawSessionData.seller_id) || sellerId),
      language: rawSessionData && Object.prototype.hasOwnProperty.call(rawSessionData, 'language') ? rawSessionData.language : null,
      session_version: 2,
      updated_at: now,
    }
  : baseSession;
return [{ json: { event, session } }];

const payload = $json ?? {};
let event = payload.event ?? null;
let session = payload.session ?? null;
try {
  if (!event) {
    event = $item(0).$node['Session Bootstrap'].json.event;
  }
  if (!session) {
    session = $item(0).$node['Session Bootstrap'].json.session;
  }
} catch {}

event = event && typeof event === 'object' ? event : {};
session = session && typeof session === 'object' ? session : {};

const source = payload.understanding || payload.data || payload.result || payload;
const allowedUserNeed = ['exploration', 'recommendation', 'clarification', 'transaction', 'info_request', 'post_sale', 'exchange_inquiry'];
const allowedNextAction = ['clarify', 'ask_one_thing', 'suggest_options', 'answer_direct', 'push_to_mini_app', 'handoff', 'notify_me'];
const allowedTentativeFlow = ['buy_soft', 'exchange_soft', 'faq', 'support', 'none'];
const allowedRouteRecommendation = ['stay_exploratory', 'soft_buy', 'soft_exchange', 'strong_faq', 'strong_support'];
const allowedAskedKeys = ['budget_etb', 'model', 'condition', 'storage', 'old_phone_details'];

const toNumber = (value, fallback) => typeof value === 'number' && Number.isFinite(value) ? value : fallback;
const clamp = (value, min, max) => Math.min(max, Math.max(min, value));
const pickEnum = (value, allowed, fallback) => allowed.includes(value) ? value : fallback;

const normalized = {
  user_need: pickEnum(source.user_need, allowedUserNeed, 'clarification'),
  next_action: pickEnum(source.next_action, allowedNextAction, 'clarify'),
  tentative_flow: pickEnum(source.tentative_flow, allowedTentativeFlow, 'none'),
  confidence: clamp(toNumber(source.confidence, 0), 0, 1),
  ambiguity: clamp(toNumber(source.ambiguity, 1), 0, 1),
  missing_information: Array.isArray(source.missing_information) ? source.missing_information.filter((v) => allowedAskedKeys.includes(v)) : [],
  route_recommendation: pickEnum(source.route_recommendation, allowedRouteRecommendation, 'stay_exploratory'),
  evidence_accumulated: Math.max(0, Math.min(5, Number.isInteger(source.evidence_accumulated) ? source.evidence_accumulated : 0)),
  reference_resolution: {
    refers_to: source.reference_resolution?.refers_to ?? null,
    resolved_id: source.reference_resolution?.resolved_id ?? null,
    resolved_entity: source.reference_resolution?.resolved_entity ?? null,
  },
  last_asked_key: allowedAskedKeys.includes(source.last_asked_key) ? source.last_asked_key : null,
};

return [{
  json: {
    event,
    session,
    event_type: event.event_type ?? 'text_message',
    message: { text: event.text ?? '' },
    callback_query: event.callback_query ?? null,
    deep_link: event.deep_link ?? null,
    ...normalized,
    validation_meta: {
      validated: true,
      source: 'validation_node',
      timestamp: Date.now(),
    },
  },
}];

const input = $json;
const session = input.session || {};
const eventType = input.event_type || 'text_message';
const message = input.message || {};
const callbackQuery = input.callback_query || null;
const deepLink = input.deep_link || null;

const understanding = {
  user_need: input.user_need ?? 'clarification',
  next_action: input.next_action ?? 'clarify',
  tentative_flow: input.tentative_flow ?? 'none',
  confidence: typeof input.confidence === 'number' ? input.confidence : 0,
  ambiguity: typeof input.ambiguity === 'number' ? input.ambiguity : 1,
  missing_information: Array.isArray(input.missing_information) ? input.missing_information : [],
  route_recommendation: input.route_recommendation ?? 'stay_exploratory',
  evidence_accumulated: Number.isInteger(input.evidence_accumulated) ? input.evidence_accumulated : 0,
  reference_resolution: input.reference_resolution || {
    refers_to: null,
    resolved_id: null,
    resolved_entity: null,
  },
  last_asked_key: input.last_asked_key ?? null,
};

const text = (message.text || '').trim().toLowerCase();
const sessionResolvedFlow = session.resolved_flow || 'none';
const sessionTentativeFlow = session.tentative_flow || 'none';
const sessionSelectedOption = session.selected_option || null;
const sessionLastAskedKey = session.last_asked_key || null;
const sessionEvidence = Number.isInteger(session.evidence_accumulated) ? session.evidence_accumulated : 0;
const errorCount = Number.isInteger(session.error_count) ? session.error_count : 0;

let decision = {
  event_type: eventType,
  resolved_flow: sessionResolvedFlow,
  tentative_flow: understanding.tentative_flow || sessionTentativeFlow || 'none',
  route_locked: sessionResolvedFlow !== 'none',
  next_action: understanding.next_action || 'clarify',
  reply_mode: 'exploratory_question',
  handoff_triggered: false,
  notify_triggered: false,
  resolver_needed: true,
  selected_option: sessionSelectedOption ? sessionSelectedOption.id || sessionSelectedOption : null,
  last_asked_key: understanding.last_asked_key || sessionLastAskedKey || null,
  decision_reason: 'default_initialization',
};

const hasStrongBuySignal = () => {
  const buyWords = ['buy', 'new phone', 'phone', 'iphone', 'samsung'];
  return buyWords.some((w) => text.includes(w));
};

const hasStrongExchangeSignal = () => {
  const exchangeWords = ['exchange', 'swap', 'trade in'];
  return exchangeWords.some((w) => text.includes(w)) || understanding.user_need === 'exchange_inquiry';
};

const hasFaqSignal = () => {
  const faqWords = ['where', 'location', 'address', 'warranty', 'delivery', 'payment', 'hours', 'policy'];
  return faqWords.some((w) => text.includes(w)) || understanding.tentative_flow === 'faq';
};

const hasSupportSignal = () => {
  const supportWords = ['problem', 'issue', 'order', 'delayed', 'help', 'support'];
  return supportWords.some((w) => text.includes(w)) || understanding.tentative_flow === 'support';
};

const isShortRefinement = () => {
  const refinementWords = ['128gb', '8/128', '8gb', 'black', 'last price', 'cheaper', 'that one', 'second one', 'first one', 'version'];
  return text.length > 0 && (refinementWords.some((w) => text.includes(w)) || understanding.reference_resolution?.refers_to !== null);
};

const wantsHuman = () => {
  const words = ['human', 'admin', 'owner', 'person', 'talk to'];
  return words.some((w) => text.includes(w));
};

if (eventType === 'start_reset') {
  decision = {
    ...decision,
    resolved_flow: 'none',
    tentative_flow: 'none',
    route_locked: false,
    next_action: 'clarify',
    reply_mode: 'neutral_clarify',
    resolver_needed: false,
    selected_option: null,
    last_asked_key: null,
    decision_reason: 'start_reset_event',
  };
} else if (eventType === 'deep_link_start') {
  decision = {
    ...decision,
    resolved_flow: 'buy',
    tentative_flow: 'buy_soft',
    route_locked: false,
    next_action: 'suggest_options',
    reply_mode: 'suggest_options',
    resolver_needed: true,
    decision_reason: 'deep_link_start_event',
  };
} else if (eventType === 'callback_action') {
  const action = callbackQuery?.data || callbackQuery?.action || 'unknown_callback';
  if (String(action).includes('select_option')) {
    decision = {
      ...decision,
      resolved_flow: sessionResolvedFlow === 'none' ? 'buy' : sessionResolvedFlow,
      tentative_flow: 'buy_soft',
      route_locked: true,
      next_action: 'suggest_options',
      reply_mode: 'confirm_selection',
      resolver_needed: true,
      decision_reason: 'callback_select_option',
    };
  } else if (String(action).includes('confirm_order')) {
    decision = {
      ...decision,
      resolved_flow: 'buy',
      tentative_flow: 'buy_soft',
      route_locked: true,
      next_action: 'answer_direct',
      reply_mode: 'confirm_selection',
      resolver_needed: true,
      decision_reason: 'callback_confirm_order',
    };
  } else if (String(action).includes('change_option')) {
    decision = {
      ...decision,
      resolved_flow: 'buy',
      tentative_flow: 'buy_soft',
      route_locked: true,
      next_action: 'suggest_options',
      reply_mode: 'suggest_options',
      resolver_needed: true,
      decision_reason: 'callback_change_option',
    };
  } else if (String(action).includes('notify')) {
    decision = {
      ...decision,
      notify_triggered: true,
      next_action: 'notify_me',
      reply_mode: 'notify_confirmation',
      resolver_needed: false,
      decision_reason: 'callback_notify_me',
    };
  } else if (String(action).includes('admin') || String(action).includes('handoff')) {
    decision = {
      ...decision,
      handoff_triggered: true,
      next_action: 'handoff',
      reply_mode: 'handoff_notice',
      resolver_needed: false,
      decision_reason: 'callback_admin_handoff',
    };
  } else {
    decision = {
      ...decision,
      next_action: 'clarify',
      reply_mode: 'neutral_clarify',
      resolver_needed: false,
      decision_reason: 'callback_unknown_safe_fallback',
    };
  }
} else if (understanding.confidence < 0.7 || understanding.ambiguity > 0.4) {
  decision = {
    ...decision,
    resolved_flow: 'none',
    tentative_flow: 'none',
    route_locked: false,
    next_action: 'clarify',
    reply_mode: 'neutral_clarify',
    resolver_needed: false,
    last_asked_key: null,
    decision_reason: 'weak_understanding_fallback',
  };
} else if (isShortRefinement() && sessionResolvedFlow === 'buy') {
  decision = {
    ...decision,
    resolved_flow: 'buy',
    tentative_flow: 'buy_soft',
    route_locked: true,
    next_action: understanding.next_action === 'answer_direct' ? 'answer_direct' : 'suggest_options',
    reply_mode: 'suggest_options',
    resolver_needed: true,
    selected_option: understanding.reference_resolution?.resolved_id || decision.selected_option,
    decision_reason: 'short_buy_refinement_inherited',
  };
} else if (isShortRefinement() && sessionResolvedFlow === 'exchange') {
  decision = {
    ...decision,
    resolved_flow: 'exchange',
    tentative_flow: 'exchange_soft',
    route_locked: true,
    next_action: 'ask_one_thing',
    reply_mode: 'exploratory_question',
    resolver_needed: true,
    decision_reason: 'short_exchange_refinement_inherited',
  };
} else if (hasFaqSignal()) {
  decision = {
    ...decision,
    resolved_flow: 'faq',
    tentative_flow: 'faq',
    route_locked: true,
    next_action: 'answer_direct',
    reply_mode: 'direct_answer',
    resolver_needed: true,
    last_asked_key: null,
    decision_reason: 'faq_override',
  };
} else if (hasSupportSignal()) {
  decision = {
    ...decision,
    resolved_flow: 'support',
    tentative_flow: 'support',
    route_locked: true,
    next_action: 'answer_direct',
    reply_mode: 'direct_answer',
    resolver_needed: true,
    last_asked_key: null,
    decision_reason: 'support_override',
  };
} else if (hasStrongExchangeSignal()) {
  decision = {
    ...decision,
    resolved_flow: 'none',
    tentative_flow: 'exchange_soft',
    route_locked: false,
    next_action: understanding.next_action || 'ask_one_thing',
    reply_mode: 'exploratory_question',
    resolver_needed: true,
    decision_reason: 'strong_exchange_soft_route',
  };
} else if (hasStrongBuySignal() || understanding.tentative_flow === 'buy_soft') {
  decision = {
    ...decision,
    resolved_flow: 'none',
    tentative_flow: 'buy_soft',
    route_locked: false,
    next_action: understanding.next_action || 'ask_one_thing',
    reply_mode: understanding.next_action === 'suggest_options' ? 'suggest_options' : 'exploratory_question',
    resolver_needed: true,
    decision_reason: 'strong_buy_soft_route',
  };
}

if (decision.resolved_flow === 'none' && understanding.confidence >= 0.85 && understanding.ambiguity <= 0.25 && (understanding.evidence_accumulated >= 2 || sessionEvidence >= 2)) {
  if (decision.tentative_flow === 'buy_soft') {
    decision.resolved_flow = 'buy';
    decision.route_locked = true;
    decision.decision_reason = 'hard_lock_buy_by_evidence';
  } else if (decision.tentative_flow === 'exchange_soft') {
    decision.resolved_flow = 'exchange';
    decision.route_locked = true;
    decision.decision_reason = 'hard_lock_exchange_by_evidence';
  } else if (decision.tentative_flow === 'faq') {
    decision.resolved_flow = 'faq';
    decision.route_locked = true;
    decision.decision_reason = 'hard_lock_faq_by_evidence';
  } else if (decision.tentative_flow === 'support') {
    decision.resolved_flow = 'support';
    decision.route_locked = true;
    decision.decision_reason = 'hard_lock_support_by_evidence';
  }
}

if (decision.next_action === 'ask_one_thing' && decision.last_asked_key && sessionLastAskedKey && decision.last_asked_key === sessionLastAskedKey && understanding.missing_information.length === 0) {
  decision.next_action = 'clarify';
  decision.reply_mode = 'neutral_clarify';
  decision.last_asked_key = null;
  decision.decision_reason = 'prevent_repeated_question';
}

if (wantsHuman() || errorCount >= 3) {
  decision.handoff_triggered = true;
  decision.next_action = 'handoff';
  decision.reply_mode = 'handoff_notice';
  decision.resolver_needed = false;
  decision.decision_reason = wantsHuman() ? 'explicit_handoff_request' : 'error_threshold_handoff';
}

if (decision.next_action === 'notify_me') {
  decision.notify_triggered = true;
  decision.reply_mode = 'notify_confirmation';
  decision.resolver_needed = false;
  decision.decision_reason = 'notify_triggered_by_decision';
}

if (!decision.decision_reason || decision.decision_reason === 'default_initialization') {
  decision = {
    ...decision,
    resolved_flow: 'none',
    tentative_flow: 'none',
    route_locked: false,
    next_action: 'clarify',
    reply_mode: 'neutral_clarify',
    resolver_needed: false,
    decision_reason: 'default_exploratory_fallback',
  };
}

return [{ json: { ...input, rules_decision: decision } }];
